# In-memory storage (replace with database in production)
users_db = {}
sessions_db = {}
login_attempts = {}

# Rate limiting configuration
MAX_LOGIN_ATTEMPTS = 5
RATE_LIMIT_WINDOW = 300  # 5 minutes in seconds


def get_client_identifier():
    """Get a unique identifier for rate limiting"""
    return hashlib.sha256(
        (request.remote_addr + request.headers.get('User-Agent', '')).encode()
    ).hexdigest()


def check_rate_limit(identifier):
    """Check if client has exceeded rate limit"""
    current_time = time.time()
    
    if identifier not in login_attempts:
        login_attempts[identifier] = []
    
    # Remove old attempts outside the window
    login_attempts[identifier] = [
        attempt_time for attempt_time in login_attempts[identifier]
        if current_time - attempt_time < RATE_LIMIT_WINDOW
    ]
    
    if len(login_attempts[identifier]) >= MAX_LOGIN_ATTEMPTS:
        return False
    
    return True


def record_login_attempt(identifier):
    """Record a failed login attempt"""
    if identifier not in login_attempts:
        login_attempts[identifier] = []
    login_attempts[identifier].append(time.time())


def generate_session_token():
    """Generate a cryptographically secure session token"""
    return secrets.token_urlsafe(32)


def create_session(user_id):
    """Create a new session for a user"""
    session_token = generate_session_token()
    session_data = {
        'user_id': user_id,
        'created_at': datetime.utcnow(),
        'expires_at': datetime.utcnow() + timedelta(hours=24),
        'ip_address': request.remote_addr
    }
    sessions_db[session_token] = session_data
    return session_token


def validate_session(session_token):
    """Validate a session token"""
    if not session_token or session_token not in sessions_db:
        return None
    
    session_data = sessions_db[session_token]
    
    # Check if session has expired
    if datetime.utcnow() > session_data['expires_at']:
        del sessions_db[session_token]
        return None
    
    # Optional: Check if IP address matches (can be disabled for mobile users)
    # if session_data['ip_address'] != request.remote_addr:
    #     return None
    
    return session_data['user_id']


def destroy_session(session_token):
    """Destroy a session"""
    if session_token in sessions_db:
        del sessions_db[session_token]


def login_required(f):
    """Decorator to require login for routes"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        session_token = session.get('session_token')
        user_id = validate_session(session_token)
        
        if not user_id:
            session.clear()
            return jsonify({'error': 'Authentication required'}), 401
        
        return f(user_id=user_id, *args, **kwargs)
    
    return decorated_function


